#include <bits/stdc++.h>
#include <iostream>
#include <vector>

class Solution {
public:
	solution() {
	}

	std::vector<std::pair<int, int>> bridges(const std::vector<std::vector<int>>& graph) {
		int n = graph.size(), m = 0;
		std::vector<bool> visited(n);
		std::vector<int> low(n, 0), disc(n, 0);
		int time = 0;
		for (int i = 0; i < n; i++) {
			if (!visited[i]) dfs(i, -1);
		}
		return {{}};
	}

template <typename T>
void dfs(int u, int father, const std::vector<std::vector<int>>& graph, std::vector<bool>& visited) {
		visited[u] = true;
		low[u] = disc[u] = time;
		time++;
		for (int v : graph[u]) {
			if (v == father) continue;
			if (low[v] != 0) low[u] = std::min(low[u], low[v]);
			else dfs(v, u);
			if (low[v] > disc[u]) edges[u][v][2] = true;
			else low[u] = std::min(low[u], low[v]);
		}
		low[u]++, time++;
		return;
	}

std::vector<std::vector<int>> edges(n * n, std::vector<int>(3, 0));
int main() {
	graph = [[0, {1, 2}]], [1, {2, 3}], [2, {0, 3}], [3, {}]];
	sol = Solution();
	print(sol.bridges(graph));
	return 0;
}
